CREATE TABLE IF NOT EXISTS public.crm_interactions ( id BIGSERIAL PRIMARY KEY, user_id UUID REFERENCES public.user_profiles(id) ON DELETE CASCADE, admin_id UUID REFERENCES public.user_profiles(id) ON DELETE SET NULL, type TEXT DEFAULT 'note', title TEXT, content TEXT, status TEXT DEFAULT 'open', created_at TIMESTAMPTZ DEFAULT NOW() ); ALTER TABLE public.crm_interactions ENABLE ROW LEVEL SECURITY; CREATE POLICY "Admins can view CRM interactions" ON public.crm_interactions FOR SELECT USING (public.is_admin()); CREATE POLICY "Admins can update CRM interactions" ON public.crm_interactions FOR UPDATE USING (public.is_admin());
